module wallace_tree_adder (
    input [3:0] a,
    input [3:0] b,
    input [3:0] c,
    output [4:0] sum
);
    wire [4:0] ab_sum;
    wire [4:0] abc_sum;

    // First stage: add a and b
      wire _n01 = a[0] ^ b[0];
  wire _c01 = a[0] & b[0];
  wire _n02 = a[1] ^ b[1] ^ _c01;
  wire _c02 = (a[1] & b[1]) | (a[1] & _c01) | (b[1] & _c01);
  wire _n03 = a[2] ^ b[2] ^ _c02;
  wire _c03 = (a[2] & b[2]) | (a[2] & _c02) | (b[2] & _c02);
  wire _n04 = a[3] ^ b[3] ^ _c03;
  wire _c04 = (a[3] & b[3]) | (a[3] & _c03) | (b[3] & _c03);
  assign ab_sum = {_n01, _n02, _n03, _n04};

    // Second stage: add the result with c
    assign abc_sum = ab_sum + c;

    // Output the final sum
    assign sum = abc_sum;

endmodule
